/*
  Tabsan EduSphere — College Demo Data (Class 11-12, Percentage Grading)
  ==================================================================
  1 Tenant x 1 Campus x 3 Depts x 15 Courses x 24 Students
  Grading: Percentage (A+ = 90%, A = 80%, B = 70%, C = 60%, D = 55%, F < 55%)
*/
IF DB_ID(N'Tabsan-EduSphere') IS NULL BEGIN RAISERROR('Run 01-Schema-Current.sql first.',16,1); RETURN; END;
GO
USE [Tabsan-EduSphere]; GO
DECLARE @Now DATETIME2=SYSUTCDATETIME(),@SAPwdHash NVARCHAR(512)=N'argon2id:kot3aIW+GTcmK4Ji/jGD7BxrNOEh57PLaFMUZrZa5oM=:v+XYusZ0Eu9Xs8Sz/7Hi58z4SrS9KsJ/ynnr/iCkkSk=',@PwdHash NVARCHAR(512)=N'argon2id:S7KBqFYDtoQ/+936WKnRGrfaizX10wKV9mIYdhbsO7M=:ncFDYnCu/jEm22iNzYCxdtkxnIZWWyRHRe7StVKmpvQ=';
DECLARE @RSA INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'SuperAdmin'),@RA INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Admin'),@RF INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Faculty'),@RS INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Student'),@RFn INT=(SELECT TOP 1 [Id] FROM [roles] WHERE [Name]=N'Finance');

/* ── TENANT & CAMPUS ── */
DECLARE @T UNIQUEIDENTIFIER=CAST('A1000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@C UNIQUEIDENTIFIER=CAST('B1000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER);
INSERT INTO [tenants] ([Id],[Code],[Name],[IsActive],[IsDeleted],[CreatedAt]) SELECT @T,N'COL',N'College Tenant',1,0,@Now WHERE NOT EXISTS(SELECT 1 FROM [tenants] WHERE [Code]=N'COL');
INSERT INTO [campuses] ([Id],[TenantId],[Code],[Name],[IsActive],[IsDeleted],[CreatedAt]) SELECT @C,@T,N'COL-MAIN',N'College Campus',1,0,@Now WHERE NOT EXISTS(SELECT 1 FROM [campuses] WHERE [Code]=N'COL-MAIN');

/* ── DEPARTMENTS (3) ── */
DECLARE @SC UNIQUEIDENTIFIER=CAST('C1000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@CM UNIQUEIDENTIFIER=CAST('C1000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@HM UNIQUEIDENTIFIER=CAST('C1000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER);
INSERT INTO [departments] ([Id],[Name],[Code],[InstitutionType],[TenantId],[CampusId],[IsActive],[IsDeleted],[CreatedAt]) SELECT d.Id,d.Name,d.Code,1,@T,@C,1,0,@Now FROM (VALUES (@SC,N'Science College',N'SCI'),(@CM,N'Commerce College',N'COM'),(@HM,N'Humanities College',N'HUM')) d(Id,Name,Code) WHERE NOT EXISTS(SELECT 1 FROM [departments] x WHERE x.[Id]=d.Id OR x.[Code]=d.Code);

/* ── PROGRAMS ── */
INSERT INTO [academic_programs] ([Id],[Name],[Code],[DepartmentId],[TotalSemesters],[MaxCreditLoadPerSemester],[IsActive],[IsDeleted],[CreatedAt]) SELECT p.Id,p.Name,p.Code,p.Did,p.S,p.Cr,1,0,@Now FROM (VALUES (CAST('D1000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),N'FSc Pre-Medical',N'FSC-MED',@SC,2,12),(CAST('D1000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),N'ICom',N'ICOM',@CM,2,12),(CAST('D1000000-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),N'FA General Arts',N'FA',@HM,2,12)) p(Id,Name,Code,Did,S,Cr) WHERE NOT EXISTS(SELECT 1 FROM [academic_programs] x WHERE x.[Id]=p.Id);

/* ── SEMESTERS (2 = Class 11, Class 12) ── */
INSERT INTO [semesters] ([Id],[Name],[StartDate],[EndDate],[IsClosed],[IsDeleted],[CreatedAt]) SELECT s.Id,s.Name,s.StartDate,s.EndDate,1,0,@Now FROM (VALUES (CAST('E1000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),N'Class 11 (2025-2026)','2025-08-01','2026-05-31'),(CAST('E1000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),N'Class 12 (2025-2026)','2025-08-01','2026-05-31')) s(Id,Name,StartDate,EndDate) WHERE NOT EXISTS(SELECT 1 FROM [semesters] x WHERE x.[Id]=s.Id);
DECLARE @Y1 UNIQUEIDENTIFIER=CAST('E1000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@Y2 UNIQUEIDENTIFIER=CAST('E1000000-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER);

/* ── COURSES (5 per dept = 15) ── */
DECLARE @Cr TABLE (Id UNIQUEIDENTIFIER,T NVARCHAR(200),Cd NVARCHAR(20),CrH INT,Did UNIQUEIDENTIFIER,CT INT,GT NVARCHAR(20));
INSERT INTO @Cr VALUES (CAST('F1000000-0000-0000-0000-000001001' AS UNIQUEIDENTIFIER),N'Physics',N'SCI-PHY',4,@SC,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000001002' AS UNIQUEIDENTIFIER),N'Chemistry',N'SCI-CHEM',4,@SC,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000001003' AS UNIQUEIDENTIFIER),N'Biology',N'SCI-BIO',4,@SC,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000001004' AS UNIQUEIDENTIFIER),N'Mathematics',N'SCI-MATH',3,@SC,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000001005' AS UNIQUEIDENTIFIER),N'Computer Science',N'SCI-CS',3,@SC,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000002001' AS UNIQUEIDENTIFIER),N'Accounting',N'COM-ACC',4,@CM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000002002' AS UNIQUEIDENTIFIER),N'Business Studies',N'COM-BUS',4,@CM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000002003' AS UNIQUEIDENTIFIER),N'Economics',N'COM-ECO',4,@CM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000002004' AS UNIQUEIDENTIFIER),N'Banking & Finance',N'COM-BNK',3,@CM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000002005' AS UNIQUEIDENTIFIER),N'Statistics',N'COM-STAT',3,@CM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000003001' AS UNIQUEIDENTIFIER),N'English Compulsory',N'HUM-ENG',3,@HM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000003002' AS UNIQUEIDENTIFIER),N'Urdu Compulsory',N'HUM-URD',3,@HM,1,N'Percentage'),(CAST('F1000000-0000-0000-0000-000003003' AS UNIQUEIDENTIFIER),N'Islamic Studies',N'HUM-ISL',3,@HM,2,N'Percentage'),(CAST('F1000000-0000-0000-0000-000003004' AS UNIQUEIDENTIFIER),N'Pakistan Studies',N'HUM-PST',3,@HM,2,N'Percentage'),(CAST('F1000000-0000-0000-0000-000003005' AS UNIQUEIDENTIFIER),N'Sociology',N'HUM-SOC',3,@HM,2,N'Percentage');
INSERT INTO [courses] ([Id],[Title],[Code],[CreditHours],[DepartmentId],[CourseType],[GradingType],[HasSemesters],[IsActive],[IsDeleted],[CreatedAt]) SELECT c.Id,c.T,c.Cd,c.CrH,c.Did,c.CT,c.GT,1,1,0,@Now FROM @Cr c WHERE NOT EXISTS(SELECT 1 FROM [courses] x WHERE x.[Id]=c.Id);

/* ── USERS ── */
DECLARE @SA UNIQUEIDENTIFIER=CAST('70000000-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@ASc UNIQUEIDENTIFIER=CAST('700000A0-0000-0000-0000-000000000001' AS UNIQUEIDENTIFIER),@ACm UNIQUEIDENTIFIER=CAST('700000A0-0000-0000-0000-000000000002' AS UNIQUEIDENTIFIER),@AHm UNIQUEIDENTIFIER=CAST('700000A0-0000-0000-0000-000000000003' AS UNIQUEIDENTIFIER),@FN UNIQUEIDENTIFIER=CAST('700000A0-0000-0000-0000-000000000004' AS UNIQUEIDENTIFIER);
INSERT INTO [users] ([Id],[Username],[Email],[PasswordHash],[RoleId],[DepartmentId],[TenantId],[CampusId],[InstitutionType],[FullName],[IsActive],[IsDeleted],[CreatedAt]) SELECT u.Id,u.Un,u.Em,u.Pwd,u.Rid,u.Did,u.Tid,u.Cid,u.It,u.Fn,1,0,@Now FROM (VALUES (@SA,N'superadmin',N'superadmin@tabsan.local',@SAPwdHash,@RSA,NULL,NULL,NULL,NULL,N'Super Admin'),(@ASc,N'admin.sci',N'asc@college.local',@PwdHash,@RA,@SC,@T,@C,1,N'Science Admin'),(@ACm,N'admin.com',N'acm@college.local',@PwdHash,@RA,@CM,@T,@C,1,N'Commerce Admin'),(@AHm,N'admin.hum',N'ahm@college.local',@PwdHash,@RA,@HM,@T,@C,1,N'Humanities Admin'),(@FN,N'finance',N'fn@college.local',@PwdHash,@RFn,@SC,@T,@C,1,N'Finance Officer')) u(Id,Un,Em,Pwd,Rid,Did,Tid,Cid,It,Fn) WHERE NOT EXISTS(SELECT 1 FROM [users] x WHERE x.[Id]=u.Id OR x.[Email]=u.Em);

